  1206→
  1207→  const session = getSession(sessionId || "anon", userId, userRole, userName);
  1208→  session.history.push({ role: "user", content: message.trim() });
  1209→  if (session.history.length > 40) session.history = session.history.slice(-40);
  1210→
  1211→  try {
  1212→    /* ── Round 1: AI decides which tools to call ── */
  1213→    const messages: any[] = [
  1214→      { role: "system", content: buildSystemPrompt(userRole, userName) },
  1215→      ...session.history.slice(-20),
  1216→    ];
  1217→
